('9825d904-2f8a-4172-8331-f97971ecc9de'::uuid, 'L-2026-009', 'Mineralwolldämmung einbauen', 'Klemmfilz in Ständerwerk', 'Einbauen von Mineralwolle-Dämmplatten in Ständer- bzw. Sparrenkonstruktion, klemmend und fugenlos verlegt.', 'e2875372-b8c2-48cb-a725-af4052e70c81'::uuid, 'm²', 6, true, null, '2026-06-16 07:15:30.207495+00'::timestamptz, '2026-06-16 17:16:12.451937+00'::timestamptz, 'Dämmung MW', 'Dämmung', 20, 'WLG 035', 9, 20, null, 'artikel', false, 'kein', 0, 0, '090', 1, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('896cb7c9-6f86-45fc-bdd1-fedb0e65d089'::uuid, '01-022', 'Grundrissplanung für Umbauarbeiten Grawe', 'Grundrissplanung für Umbauarbeiten Grawe', 'Erstellen einer Grundrissplanung für die geplanten Umbauarbeiten auf Basis der vorhandenen Konsenspläne und der vor Ort aufgenommenen Naturmaße. Beinhaltet das Einzeichnen sämtlicher Bauteile, Fenster, Türen und Raummaße sowie die Erstellung von zwei Planungsvarianten, die im Preis bereits inkludiert sind. Die Planung dient als Grundlage für weitere Entwurfs-, Einreich- oder Ausführungsphasen.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'm²', 0, true, null, '2026-06-24 13:01:35.142307+00'::timestamptz, '2026-07-07 04:28:36.037972+00'::timestamptz, null, null, 20, 'Hero ID: 510249 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 3.73, 'artikel', false, 'kein', 0, 0, null, 10, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, 'Mindestverrechnung: 290,00 € Pauschal', null),
('bca45f05-4e5e-4561-9d3a-6b4939bd12b8'::uuid, 'L-2026-001', 'Mauerwerk 25 cm herstellen', 'Hochlochziegel 25 cm inkl. Mörtel', 'Herstellen von tragendem Mauerwerk aus Hochlochziegeln 25 cm Stärke im Dünnbettmörtelverfahren, inkl. Versetzen, Ausrichten, Verfugen und Reinigen. Ausführung gemäß ÖNORM B 2110, Stein in Druckfestigkeitsklasse nach Statik.', 'd6e77858-bb87-431e-9da6-ff224e0cca58'::uuid, 'm²', 7, true, null, '2026-06-16 07:15:30.207495+00'::timestamptz, '2026-06-16 07:15:30.207495+00'::timestamptz, 'Mauerwerk 25', 'Rohbau', 20, 'Steinlieferung bauseits möglich', 1, 20, null, 'artikel', false, 'kein', 0, 0, '010', 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('955d7739-646d-4661-a1db-b316547e4886'::uuid, 'L-2026-002', 'Stahlbetondecke herstellen', 'Schalung, Bewehrung, Beton C25/30', 'Herstellen einer Stahlbetondecke inkl. Schalung, Bewehrungsmatten, Betonieren mit C25/30, Verdichten und Abziehen. Ausschalen nach Erreichen der Ausschalfestigkeit.', 'd6e77858-bb87-431e-9da6-ff224e0cca58'::uuid, 'm²', 7, true, null, '2026-06-16 07:15:30.207495+00'::timestamptz, '2026-06-16 07:15:30.207495+00'::timestamptz, 'STB-Decke', 'Rohbau', 20, 'Statik beachten', 2, 22, null, 'artikel_pauschale', true, 'prozent_material', 0, 6, '020', 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('48307377-fe3b-47f2-aa29-fab5906ccf34'::uuid, 'L-2026-003', 'Zementestrich verlegen 5 cm', 'Estrich CT-C25-F4, 5 cm', 'Liefern und Einbauen eines Zementestrichs CT-C25-F4 in 5 cm Stärke auf Trennlage, inkl. Abziehen und Glätten, begehbar nach Norm-Aushärtung.', 'd6e77858-bb87-431e-9da6-ff224e0cca58'::uuid, 'm²', 6, true, null, '2026-06-16 07:15:30.207495+00'::timestamptz, '2026-06-16 07:15:30.207495+00'::timestamptz, 'Estrich 5cm', 'Estrich', 20, 'Randdämmstreifen separat', 3, 20, null, 'artikel', false, 'kein', 0, 0, '030', 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('936044c3-009d-450b-9fa5-47de74d12885'::uuid, 'L-2026-006', 'Mauerwerk abbrechen', 'Nichttragende Wände, Ziegel', 'Abbruch nichttragender Ziegelwände inkl. Werkzeug, Staubschutz und Abtransport zum Container. Sorgfältige Arbeit zum Schutz angrenzender Bauteile.', 'ec22d11c-c0f7-46a0-a84b-8752a6c472c5'::uuid, 'm²', 5, true, null, '2026-06-16 07:15:30.207495+00'::timestamptz, '2026-06-16 07:15:30.207495+00'::timestamptz, 'Wand Abbruch', 'Abbruch', 20, 'Tragwerk vorher prüfen', 6, 18, null, 'pauschale_fix', true, 'fix', 6, 0, '060', 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
