('82cb6738-c746-4d0f-a457-0f2796716997'::uuid, '01-011', 'Beweissicherung vor Abbrucharbeiten', 'Beweissicherung vor Abbrucharbeiten', 'Durchführen einer umfassenden Beweissicherung mittels Fotodokumentation vor Beginn der Abbrucharbeiten. Die Dokumentation umfasst den Zustand der Nachbarwohnung unterhalb, der angrenzenden Wohnungen sowie sämtlicher Bereiche entlang des gesamten Transportweges. Ziel ist die lückenlose Erfassung des Bestandszustands zur Absicherung vor eventuellen Schadensansprüchen.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:01:23.026062+00'::timestamptz, '2026-07-07 04:28:36.048367+00'::timestamptz, null, null, 20, 'Hero ID: 510098 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 196, 'artikel', false, 'kein', 0, 0, null, 13, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
