('04651497-0c29-4ada-84c0-756885fdafed'::uuid, '01-032', 'Aufpreis für erweitertes Einreichverfahren gemäß § 70 / § 71 BO Wien', 'Aufpreis für erweitertes Einreichverfahren gemäß § 70 / § 71 BO Wien', 'Zusatzaufwand für die Durchführung eines erweiterten Einreichverfahrens gemäß § 70 bzw. § 71 der Bauordnung für Wien im Zuge der Sanierung einer Wohnung, eines Büros oder eines Lokals, wenn ein bewilligungspflichtiges Verfahren erforderlich ist. Beinhaltet die Erstellung ergänzender Unterlagen, die Kommunikation mit der Baubehörde sowie sämtliche anfallenden Gebühren und Verwaltungsaufwendungen. Das Einholen der Unterschriften von Nachbarn oder Miteigentümern ist nicht im Preis enthalten. Diese Position ist als Aufpreis zur Einreichplanung gemäß § 62 BO Wien zu verstehen.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:01:38.408873+00'::timestamptz, '2026-06-24 13:25:42.524772+00'::timestamptz, null, null, 20, 'Hero ID: 510439 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 336, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('a3d9d9d9-19d9-4b73-a9c2-d6280bb153e1'::uuid, '01-041', 'Bestätigung des baurechtlichen Geschäftsführers', 'Bestätigung des baurechtlichen Geschäftsführers', 'Erstellung einer Bestätigung durch den baurechtlichen Geschäftsführer zur Vorlage bei der Baubehörde im Rahmen der Einreichung gemäß den Vorgaben des Magistrats. Beinhaltet die Prüfung der Einreichunterlagen, die formelle Freigabe und Unterfertigung durch den baurechtlichen Geschäftsführer sowie die Übermittlung an die Behörde.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:01:42.740341+00'::timestamptz, '2026-06-24 13:25:46.278974+00'::timestamptz, null, null, 20, 'Hero ID: 510857 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 449.87, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('a16b4cf8-0106-4621-abdd-0e1ae92238d0'::uuid, '01-030', 'Einreichplanung gemäß § 62 BO Wien', 'Einreichplanung gemäß § 62 BO Wien', 'Herstellen der technischen Zeichnungen aufgrund einer Grundrissänderung für die Einreichplanung gemäß § 62 der Bauordnung für Wien. Beinhaltet das Erstellen der geänderten Grundrisspläne, das Einreichen der Unterlagen bei der Baupolizei, das Einholen aller erforderlichen Unterschriften sowie sämtliche anfallenden Gebühren und Abgaben. Abrechnung erfolgt pro m² Bodenfläche der betroffenen Einheit.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'm²', 0, true, null, '2026-06-24 13:01:36.416234+00'::timestamptz, '2026-06-26 11:52:06.023694+00'::timestamptz, null, null, 20, 'Hero ID: 510413 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 19.13, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, '1     m²  -   99 m² = 19,13 € / m², mindestens    930,00 € 
