('1dd2a64c-e4ec-4c62-85ea-3f398b41ccac'::uuid, '01-045', 'Baustellenbegleitung / Überprüfung statischer Ausführung', 'Baustellenbegleitung / Überprüfung statischer Ausführung', 'Begleitende Kontrolle der statisch relevanten Bauteile während der Ausführung durch den verantwortlichen Zivilingenieur. Beinhaltet die Überprüfung der Einbausituation, Bewehrung, Stahlquerschnitte und Anschlüsse sowie die Freigabe der statisch relevanten Arbeiten mittels Befund oder Bestätigung.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:02:00.155254+00'::timestamptz, '2026-06-26 11:52:06.023694+00'::timestamptz, null, null, 20, 'Hero ID: 510866 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, 'Preis für 1 Stk. Stahlrahmen 590,00 €Andere Arbeiten bei Statiker anfragen', null),
('d8b3f066-8322-49bb-a61f-af2c0eb7abc9'::uuid, '01-046', 'Prüfingenieurtätigkeit (von der Behörde vorgeschrieben)', 'Prüfingenieurtätigkeit (von der Behörde vorgeschrieben)', 'Durchführung der Prüfung der statischen Unterlagen durch einen befugten Prüfingenieur, wenn diese durch die Behörde verlangt wird. Beinhaltet die Kontrolle der statischen Berechnung, Überprüfung der Plausibilität und Sicherheitsnachweise, sowie die Erstellung des Prüfberichts zur Vorlage bei der Baubehörde.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:02:01.467301+00'::timestamptz, '2026-06-24 13:25:50.461326+00'::timestamptz, null, null, 20, 'Hero ID: 510869 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('6dad7922-e7c0-481b-a7d9-1864072a6c10'::uuid, '01-051', 'Installationsplanung für Elektro- und Haustechnikgewerke', 'Installationsplanung für Elektro- und Haustechnikgewerke', 'Herstellen einer Installationsplanung für Elektriker und Installateur auf Basis der vorhandenen technischen Zeichnungen. Beinhaltet die Eintragung sämtlicher Anschlüsse, Sanitärobjekte, Steckdosen, Schalter und Beleuchtungspunkte sowie die Koordination der Installationszonen zwischen den Gewerken. Abrechnung erfolgt pro m² Bodenfläche der geplanten Einheit.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'm²', 0, true, null, '2026-06-24 13:02:03.222017+00'::timestamptz, '2026-06-24 13:25:52.333633+00'::timestamptz, null, null, 20, 'Hero ID: 510876 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 11.2, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('327fb6ac-53ac-442b-84c2-0eab54ab4495'::uuid, '01-052', 'Einfache Möbelplanung auf vorhandener technischer Zeichnung', 'Einfache Möbelplanung auf vorhandener technischer Zeichnung', 'Herstellen einer einfachen Möbelplanung auf Basis der vorhandenen technischen Zeichnungen. Beinhaltet die Eintragung der geplanten Möblierung (z. B. Küchen, Schränke, Sitzmöbel, Sanitäreinrichtungen) sowie die Anpassung an Raummaße, Fenster- und Türsituationen. Die Planung dient zur räumlichen Darstellung und Abstimmung der Ausstattung. Abrechnung erfolgt pro m² Bodenfläche der geplanten Einheit.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'm²', 0, true, null, '2026-06-24 13:02:04.980505+00'::timestamptz, '2026-06-24 13:25:53.12154+00'::timestamptz, null, null, 20, 'Hero ID: 510879 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 3.83, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('78d5f7cd-0fdb-4757-a090-6e9253d508e7'::uuid, '01-053', 'Fliesenplanung auf vorhandener technischer Zeichnung', 'Fliesenplanung auf vorhandener technischer Zeichnung', 'Herstellen einer Fliesenplanung auf Basis der vorhandenen technischen Zeichnungen. Beinhaltet die Darstellung der Verlegeflächen und Fugenbilder, die Festlegung des Formats, der Verlegerichtung und der Übergänge sowie die Zuordnung der einzelnen Fliesentypen zu Wand- und Bodenbereichen. Abrechnung erfolgt pro m² geplanter Fliesenfläche.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'm²', 0, true, null, '2026-06-24 13:02:07.812078+00'::timestamptz, '2026-06-24 13:25:54.002981+00'::timestamptz, null, null, 20, 'Hero ID: 510881 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 4.11, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('b94029ed-6305-4299-8f54-5969df5b5b66'::uuid, '01-060', 'Beantragung von Parkflächenabsperrung (2.–23. Bezirk)', 'Beantragung von Parkflächenabsperrung (2.–23. Bezirk)', 'Durchführen der behördlichen Einreichung und Genehmigung einer Parkflächenabsperrung im öffentlichen Raum der Bezirke 2 bis 23 für den Antransport und die Lagerung von Materialien (ca. 20 m², Dauer 2 Monate). Beinhaltet das Erwirken des positiven Bescheides, den Termin vor Ort mit der Behörde sowie alle anfallenden Verwaltungsgebühren und Abgaben.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:02:09.220442+00'::timestamptz, '2026-06-24 13:25:56.236262+00'::timestamptz, null, null, 20, 'Hero ID: 510886 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 540, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('17f57826-5c1d-47a5-9551-a1a04030f43c'::uuid, '01-061', 'Beantragung von Parkflächenabsperrung (1. Bezirk)', 'Beantragung von Parkflächenabsperrung (1. Bezirk)', 'Durchführen der behördlichen Einreichung und Genehmigung einer Parkflächenabsperrung im öffentlichen Raum des 1. Bezirks für den Antransport und die Lagerung von Materialien (ca. 20 m², Dauer von 2 Monaten). Beinhaltet das Erwirken eines positiven Bescheides, die Verhandlung und Terminabstimmung mit den zuständigen Behörden vor Ort sowie alle anfallenden Verwaltungsgebühren und Abgaben.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:02:10.552349+00'::timestamptz, '2026-06-24 13:25:57.05532+00'::timestamptz, null, null, 20, 'Hero ID: 510891 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 780, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('5772d9f2-58ba-48b6-b60b-c28f47b2bcd4'::uuid, '01-997', 'Regiestunden Techniker / Bauleiter', 'Regiestunden Techniker / Bauleiter', 'Regiestunden Techniker / Bauleiter für', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'Std', 0, false, null, '2026-06-24 13:02:23.692455+00'::timestamptz, '2026-06-24 21:13:21.643564+00'::timestamptz, null, null, 20, 'Hero ID: 510930 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 112, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), true, false, false, false, null, null, null),
('ad4d5ea4-b38f-42a5-b765-e0b12760bd9f'::uuid, '01-062', 'Herstellen von Parkflächenabsperrung gemäß behördlicher Genehmigung', 'Herstellen von Parkflächenabsperrung gemäß behördlicher Genehmigung', 'Herstellen einer Parkflächenabsperrung im öffentlichen Raum gemäß den Vorgaben des Magistrats. Beinhaltet das Auf- und Abbauen der erforderlichen Verkehrszeichen und Hinweisschilder, die vorschriftsmäßige Nachtbeleuchtung bzw. Warnleuchten, sowie das ständige Vorhalten der Absperrung für die Dauer von der gültigen Genehmigung. Ausführung gemäß den geltenden Verkehrs- und Sicherheitsvorschriften der Stadt Wien.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:02:12.189024+00'::timestamptz, '2026-06-24 13:25:57.957832+00'::timestamptz, null, null, 20, 'Hero ID: 510902 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 210, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('5573d35e-89e7-4772-bc8e-f0f7b8974efc'::uuid, '01-063', 'Herstellen von Bauzaun für Parkflächenabsperrung', 'Herstellen von Bauzaun für Parkflächenabsperrung', 'Herstellen einer Bauzaunabsperrung zur Sicherung der Parkfläche (ca. 10 × 2 m) gemäß behördlicher Genehmigung. Beinhaltet das sturm- und standsichere Aufstellen und Befestigen der Zaunelemente, das Vorhalten für die Dauer von 2 Monaten sowie den Abbau und Abtransport nach Fertigstellung der Arbeiten. Ausführung gemäß den Sicherheits- und Verkehrsauflagen der Stadt Wien.Jeder weitere Monat + 160,- €.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:02:13.312637+00'::timestamptz, '2026-06-24 13:25:59.252572+00'::timestamptz, null, null, 20, 'Hero ID: 510910 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 810, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('aa79adf7-7adf-4239-87c7-eaa18894f19b'::uuid, '01-070', 'Aufzugabdeckung zum Schutz bei Material- und Abbruchtransporten', 'Aufzugabdeckung zum Schutz bei Material- und Abbruchtransporten', 'Herstellen einer Aufzugabdeckung zum Schutz der Kabinenwände, Türen und Bodenflächen während des Transports von Baumaterialien und Abbruchmaterial. Beinhaltet das Anbringen von stoß- und kratzfestem Schutzmaterial, die sichere Befestigung und Anpassung an die vorhandene Aufzugseinrichtung, sowie den Abbau und die fachgerechte Entsorgung nach Abschluss der Arbeiten.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:02:14.021808+00'::timestamptz, '2026-06-24 13:26:00.462865+00'::timestamptz, null, null, 20, 'Hero ID: 510922 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 336.67, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('f6bb75f1-7e9f-46cc-b82f-de83c64e1527'::uuid, '01-071', 'Aufstellen von mobilem WC''s', 'Aufstellen von mobilem WC''s', 'Aufstellen eines mobilen WC-Containers auf der Baustelle inklusive An- und Abtransport, Auf- und Abbau, sowie betriebsbereiter Inbetriebnahme. Beinhaltet die regelmäßige Reinigung, Entleerung und Wartung für die Dauer von 1 Monat, gemäß den geltenden hygienischen Vorschriften.Jeder weitere Monat + 135,- €.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'Monat(e)', 0, true, null, '2026-06-24 13:02:14.919502+00'::timestamptz, '2026-06-24 13:26:01.632717+00'::timestamptz, null, null, 20, 'Hero ID: 510926 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 260, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('cbecc632-ee59-4bdd-b54b-e6b3e31ff6c2'::uuid, '01-072', 'Aufstellen von Seilwinde für Materialtransport', 'Aufstellen von Seilwinde für Materialtransport', 'Aufstellen einer Seilwinde mit Aufhängung für den Materialtransport auf der Baustelle, inklusive sturm- und kippsicherer Befestigung. Beinhaltet das Vorhalten der Anlage für die gesamte Dauer der Baustelle, die tägliche Sicherheitsüberprüfung gemäß den geltenden Arbeitsschutzvorschriften, sowie den Abbau und Abtransport nach Fertigstellung der Arbeiten.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:02:16.33649+00'::timestamptz, '2026-06-24 13:26:04.931989+00'::timestamptz, null, null, 20, 'Hero ID: 510927 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 570, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('7bdbc1b4-40d0-4ff9-a8a5-466bf6805d3b'::uuid, '01-073', 'Aufpreis für besonders langen Transportweg durch Stiegenhaus und/oder Hof', 'Aufpreis für besonders langen Transportweg durch Stiegenhaus und/oder Hof', 'Aufpreis für den Mehraufwand beim Materialtransport durch das Stiegenhaus und/oder den Hof aufgrund eines besonders langen oder erschwerten Transportweges. Gilt gewerkeübergreifend für alle beteiligten Professionisten und beinhaltet den zusätzlichen Zeit- und Personalaufwand für das Tragen, Sichern und Transportieren von Materialien, Werkzeugen und Geräten.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:02:17.0965+00'::timestamptz, '2026-06-24 13:26:06.081215+00'::timestamptz, null, null, 20, 'Hero ID: 510928 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('9e0da4a9-0189-4d12-9411-b5f3fb1c70ec'::uuid, '01-033', 'Einreichplanung gemäß § 70 BO Wien – Umbauten', 'Einreichplanung gemäß § 70 BO Wien – Umbauten', 'Erstellen der vollständigen Einreichplanung gemäß § 70 der Bauordnung für Wien für Umbauten, inklusive aller erforderlichen Unterlagen für die Einreichung bei der Baubehörde. Beinhaltet die Erstellung sämtlicher Einreichpläne (Grundrisse, Schnitte, Ansichten), die Einarbeitung der baurechtlich relevanten Angaben wie Bauplatzgrenzen, Baufluchten, Abstände, Höhenkoten, Raumwidmungen und Nutzflächen sowie die Darstellung sämtlicher geplanten Bauteile und Materialien.Ebenfalls inkludiert sind:das Einholen der erforderlichen Unterschriften der Auftraggeber und Miteigentümer,die Erstellung der Bau- und Flächenberechnungen,die Ausarbeitung der Beschreibungen und Formulare für die Behörde,sowie die Abgabe der vollständigen Einreichunterlagen bei der zuständigen Baubehörde.
Das Einholen der Unterschriften der Nachbarn ist nicht im Preis enthalten und wird gegebenenfalls gesondert verrechnet.Abrechnung erfolgt pro m² Bodenfläche des betroffenen Projektes.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:01:39.912752+00'::timestamptz, '2026-06-26 11:52:06.023694+00'::timestamptz, null, null, 20, 'Hero ID: 510454 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, 'Haus   30 m² - 149 m² = 2.600,00 € Pauschal
Haus 150 m² - 299 m² = 3.950,00 € Pauschal', null),
('d6e56427-a6b4-49ae-a127-800ecb931cc7'::uuid, '01-996', 'Variable Pauschalposition Gemeinkosten mit Zeit- und Materialangabe ', 'Variable Pauschalposition Gemeinkosten mit Zeit- und Materialangabe ', 'Variable Pauschalposition Gemeinkosten mit Zeit- und Materialangabe', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, false, null, '2026-06-24 13:02:22.020966+00'::timestamptz, '2026-06-24 21:13:21.643564+00'::timestamptz, null, null, 20, 'Hero ID: 510929 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), true, false, false, false, null, null, null),
('f13fb59c-c5f3-4c84-9496-5a60b7e0ce88'::uuid, '01-050', 'Erstellung eines Leistungsverzeichnisses für alle Gewerke', 'Erstellung eines Leistungsverzeichnisses für alle Gewerke', 'Herstellen eines vollständigen Leistungsverzeichnisses für sämtliche im Projekt erforderlichen Gewerke. Beinhaltet die Ermittlung und Angabe aller notwendigen Mengen und Aufmaße, die Beschreibung der vorgesehenen Materialien, sowie die Darstellung der vorgesehenen Ausführungsarten und technischen Details. Das Leistungsverzeichnis umfasst sämtliche Bau-, Installations-, Elektro- und Ausbaubereiche, die für die Umsetzung des Projektes erforderlich sind, und dient als Grundlage für die Ausschreibung, Kalkulation und Angebotslegung.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:02:02.428588+00'::timestamptz, '2026-06-26 11:52:06.023694+00'::timestamptz, null, null, 20, 'Hero ID: 510873 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, 'Schätzung des Umsatzes und dann 1,5% davon', null),
