('6dd8c54e-4e7b-41a0-8e26-25ea1ed5660d'::uuid, '01-043', 'Statische Vorbemessung', 'Statische Vorbemessung', 'Erstellung einer statischen Vorbemessung zur Beurteilung der Tragfähigkeit bei geplanten Eingriffen in die bestehende Struktur (z. B. Einbau eines Stahlrahmens, Wanddurchbruch, Abfangung). Beinhaltet die Aufnahme der Bestandsverhältnisse, die Vorbemessung der notwendigen Querschnitte und Träger, sowie eine schriftliche Kurzbewertung als Grundlage für die Einreichplanung und Kostenschätzung.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:01:56.394378+00'::timestamptz, '2026-06-26 11:52:06.023694+00'::timestamptz, null, null, 20, 'Hero ID: 510861 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, 'Preis für 1 Stk. Stahlrahmen 950,00 €Andere Arbeiten bei Statiker anfragen', null),
('0cc096ab-3ca8-4110-adab-7271520b7d07'::uuid, '01-044', 'Ingenieurbefund / Statische Berechnung gemäß § 62 / § 70 BO Wien', 'Ingenieurbefund / Statische Berechnung gemäß § 62 / § 70 BO Wien', 'Ausarbeitung einer statischen Berechnung (Ingenieurbefund) für die Einreichung bei der Baubehörde gemäß § 62 oder § 70 der Bauordnung für Wien. Beinhaltet die vollständige statische Berechnung und Dimensionierung sämtlicher betroffener Bauteile (z. B. Stahlrahmen, Unterzüge, Abfangungen, Öffnungen in tragenden Wänden) einschließlich Darstellung der Berechnungsannahmen, Nachweise und Unterschrift eines befugten Zivilingenieurs. Dient als Beilage zur Einreichung bei der Baubehörde.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:01:57.3041+00'::timestamptz, '2026-06-26 11:52:06.023694+00'::timestamptz, null, null, 20, 'Hero ID: 510864 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, 'Preis für 1 Stk. Stahlrahmen 835,00 €Andere Arbeiten bei Statiker anfragen', null),
