('833f5b53-34a0-4951-a2ea-3422121bd24d'::uuid, '03-313', 'Demontieren und Wiedermontieren von Holzverkleidung bei Fensternische', 'Demontieren und Wiedermontieren von Holzverkleidung bei Fensternische', 'Bestehende Holzverkleidung bei Fensternische im unteren Bereich sorgfältig demontieren, um den Einbau von Heizungsleitungen zu ermöglichen. Nach Abschluss der Installationsarbeiten fachgerechte Wiedermontage der Holzverkleidung einschließlich Anpassung und Nachbearbeitung der Anschlüsse für ein sauberes Erscheinungsbild.', 'bce71cf3-b8df-4af3-be7e-6e9e2b57b7c0'::uuid, 'Stk', 0, true, null, '2026-06-24 13:05:57.025236+00'::timestamptz, '2026-06-24 13:29:42.854154+00'::timestamptz, null, null, 20, 'Hero ID: 517978 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 70.93, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
