('13612c0d-1881-4aeb-a4a0-e1bac5f1892d'::uuid, '01-020', 'Pläne ausheben bei der Baubehörde', 'Pläne ausheben bei der Baubehörde', 'Ausheben der Bestandspläne bei der zuständigen Baubehörde zur Feststellung des baubehördlichen Konsensstandes, inklusive aller anfallenden Gebühren und Terminvereinbarung bei der Behörde. Beinhaltet das Kopieren der relevanten Geschosse (darüberliegend, darunterliegend sowie Kellergeschoss) sowie das Kopieren des Hausschnittes für statische Arbeiten.', '1f5f6270-f02a-403c-b7db-cfa35ed5ef09'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:01:32.597443+00'::timestamptz, '2026-07-07 04:28:36.059562+00'::timestamptz, null, null, 20, 'Hero ID: 510234 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 249, 'artikel', false, 'kein', 0, 0, null, 10, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
