('ec476bbb-62d4-4a0a-b113-5e959761db18'::uuid, '05-180', 'Elektroinstallation für Jalousien mit Schalter und Stromversorgung', 'Elektroinstallation für Jalousien mit Schalter und Stromversorgung', 'Herstellen einer kompletten Elektroinstallation für eine elektrische Jalousie, inklusive Lieferung und Verlegung der Zuleitung vom Verteiler bis zum Jalousie-Schalter und weiter bis zum Motoranschluss. Inklusive Lieferung und Montage des Jalousieschalters (Auf/Ab-Funktion) und Anschluss an den bestehenden Stromkreis oder eigene Absicherung.', '90938716-f28e-40cd-9457-ca1e7da6ebb6'::uuid, 'Stk', 0, true, null, '2026-06-24 13:07:29.198559+00'::timestamptz, '2026-06-24 13:30:57.470938+00'::timestamptz, null, null, 20, 'Hero ID: 519959 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 156, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('51b665de-e996-41dd-83db-5d0ee4a2de52'::uuid, '05-190', 'Leerverrohrung für Alarmanlage mit Leerverrohrung und Zentrale', 'Leerverrohrung für Alarmanlage mit Leerverrohrung und Zentrale', 'Herstellen einer Leerverrohrung für eine Alarmanlage pro Stück Sensor und/oder Melder, inklusive Lieferung und Verlegung der Leerverrohrungen für Melder, Sensoren, Zentralle und Bedienteile. Montage der Zuleitung und Anschlussmöglichkeit an die Alarmzentrale, inklusive Stromversorgung, Absicherung, Beschriftung und Funktionsprüfung. Beinhaltet das Setzen von Dosen, Leitungsverlegung unter Putz, Durchführung durch Wände und Fixierung.', '90938716-f28e-40cd-9457-ca1e7da6ebb6'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:07:30.17692+00'::timestamptz, '2026-06-24 13:31:03.196642+00'::timestamptz, null, null, 20, 'Hero ID: 519961 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('8a4e981f-c3b4-4c76-95f5-8551898cf7fb'::uuid, '05-200', 'Elektroinstallation für EDV-Installation herstellen', 'Elektroinstallation für EDV-Installation herstellen', 'Herstellen einer kompletten Elektroinstallation für EDV-Anschlüsse inklusive Lieferung und Verlegung von Datenleitungen (Cat 7), Setzen der Unterputzdosen, Montage der Netzwerkanschlüsse (RJ45), Anschluss an den vorgesehenen Medienverteiler bzw. Netzwerkschrank sowie Durchführung von Leitungen und Abdichtung der Wanddurchführungen. Inklusive Beschriftung, Messung der Leitungswiderstände, Dokumentation und Funktionsprüfung. Alle erforderlichen Stemmarbeiten, Leitungen, Dosen, Anschlussmaterialien und Wiederherstellungsarbeiten sind enthalten.', '90938716-f28e-40cd-9457-ca1e7da6ebb6'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:07:31.053967+00'::timestamptz, '2026-06-24 13:31:04.025277+00'::timestamptz, null, null, 20, 'Hero ID: 519962 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('35f88a16-bc4d-421f-aaf0-82101558103f'::uuid, '05-210', 'Herstellen von CAT 6 Twin Dateninstallation (Unterputz)', 'Herstellen von CAT 6 Twin Dateninstallation (Unterputz)', 'Herstellen einer Dateninstallation mit CAT 6 Twin Leitung, inklusive Lieferung und Verlegung der Twin-Leitung (Doppelleitung), Setzen der Unterputzdose, Montage von zwei RJ45-Datenanschlüssen, Anschluss an den vorgesehenen Medienverteiler bzw. Patchfeld sowie Durchführung, Befestigung, Beschriftung und Funktionsprüfung. Inklusive aller erforderlichen Stemmarbeiten, Leitungsmaterialien, Anschlusszubehör, Kleinmaterialien und Abdichtungen.', '90938716-f28e-40cd-9457-ca1e7da6ebb6'::uuid, 'Stk', 0, true, null, '2026-06-24 13:07:32.647847+00'::timestamptz, '2026-06-24 13:31:04.866187+00'::timestamptz, null, null, 20, 'Hero ID: 519967 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 440, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
