('2a13f41d-e4cd-400f-bd9e-707991037742'::uuid, '05-212', 'Liefern und Montieren von 2 Stk. EDV-Anschlussdosen inkl. Pin-Messung', 'Liefern und Montieren von 2 Stk. EDV-Anschlussdosen inkl. Pin-Messung', '2 Stk. EDV-Anschlussdosen liefern und fachgerecht montieren, inklusive Setzen der Unterputzdosen, Anschluss der Datenleitungen (CAT 6 oder CAT 7) mittels LSA-Anschlusstechnik, Montage der Abdeckungen und Durchführung einer vollständigen Pin-Messung auf beiden Seiten (Dose und Patchfeld). Inklusive Beschriftung der Anschlüsse, Prüfprotokoll, Funktionskontrolle, aller Befestigungs- und Anschlussmaterialien sowie Kleinmaterialien.', '90938716-f28e-40cd-9457-ca1e7da6ebb6'::uuid, 'Stk', 0, true, null, '2026-06-24 13:07:36.117938+00'::timestamptz, '2026-06-24 13:31:09.102026+00'::timestamptz, null, null, 20, 'Hero ID: 520018 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 525, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('4dd9d359-0400-418c-bf29-9076f398bdef'::uuid, '05-220', 'Schalterprogramm in gesamter Wohnung auf Berker S1 (matt oder glänzend) tauschen', 'Schalterprogramm in gesamter Wohnung auf Berker S1 (matt oder glänzend) tauschen', 'Aufpreis für die Ausführung sämtlicher Schalter, Steckdosen und Abdeckungen in der gesamten Wohnung mit dem Schalterprogramm Berker S1, reinweiß glänzend oder matt, anstelle der Standardausführung.', '90938716-f28e-40cd-9457-ca1e7da6ebb6'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:07:38.414626+00'::timestamptz, '2026-06-24 13:31:10.16997+00'::timestamptz, null, null, 20, 'Hero ID: 520021 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('b079104d-1427-438a-bebc-5028883c8719'::uuid, '05-230', 'Türöffner herstellen', 'Türöffner herstellen', 'Herstellen eines Stromauslasses für den elektrischen Türöffner. Durchführung sämtlicher Arbeiten vom bestehenden Anschluss bis zur Tür, fachgerechtes Verlegen und Anschluss der Leitung, Montage der Anschlussdose, Anschluss an das Verriegelungsmodul und Funktionsprüfung.', '90938716-f28e-40cd-9457-ca1e7da6ebb6'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:07:39.477788+00'::timestamptz, '2026-06-24 13:31:11.672177+00'::timestamptz, null, null, 20, 'Hero ID: 520024 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 210, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('6d22225e-c6aa-4287-ba0d-601c5cee98c7'::uuid, '05-250', 'Elektrobefund', 'Elektrobefund', 'Prüfung der bestehenden Elektroanlage nach Abschluss der Arbeiten, Sichtprüfung, Durchgangs- und Isolationsmessung gemäß ÖVE/ÖNORM E 8001, Erstellung des Prüfprotokolls mit Messergebnissen und Beurteilung des Anlagenzustands. Übergabe an den Auftraggeber zur Dokumentation.', '90938716-f28e-40cd-9457-ca1e7da6ebb6'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:07:40.677781+00'::timestamptz, '2026-06-24 13:31:12.663975+00'::timestamptz, null, null, 20, 'Hero ID: 517291 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 498.29, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
