('cadd4b1f-925c-4ef9-8276-2fe11e76c363'::uuid, '05-261', 'Therme mit Raumthermostat anschließen', 'Therme mit Raumthermostat anschließen', 'Therme mit Raumthermostat elektrisch anschließen, Leitungen vom Verteiler zur Therme verlegen, Anschluss an vorhandene Stromversorgung herstellen, Steuerleitung zum Raumthermostat anschließen, Funktion prüfen und Regelung testen.', '90938716-f28e-40cd-9457-ca1e7da6ebb6'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:07:45.812292+00'::timestamptz, '2026-06-24 13:31:15.451408+00'::timestamptz, null, null, 20, 'Hero ID: 519369 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 121.9, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
