('39b3547e-73f1-4e09-a519-a715e88e5229'::uuid, '07-085', 'Aufpreis für Estrich fußbodenheizungstauglich bei Maschinenestrich', 'Aufpreis für Estrich fußbodenheizungstauglich bei Maschinenestrich', 'Aufpreis für das Herstellen eines maschinell eingebrachten Maschinenestrichs, der für Fußbodenheizungen geeignet ist. Der Estrich wird mit speziell abgestimmtem Zuschlägen hergestellt, um eine erhöhte Wärmeleitfähigkeit und gleichmäßige Wärmeverteilung sicherzustellen. Sämtliche Anforderungen laut ÖNORM B 3732 werden eingehalten.', 'd6e77858-bb87-431e-9da6-ff224e0cca58'::uuid, 'm²', 0, true, null, '2026-06-24 13:13:30.450139+00'::timestamptz, '2026-06-24 13:13:30.450139+00'::timestamptz, null, null, 20, 'Hero ID: 518324 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 6.5, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('ff25245d-dfdb-4c63-b4a3-9e4b9b051e92'::uuid, '07-086', 'Aufpreis für schnell trocknenden Maschinenestrich, 2 Wochen', 'Aufpreis für schnell trocknenden Maschinenestrich, 2 Wochen', 'Aufpreis für die Herstellung eines schnell trocknenden Maschinenestrichs mit beschleunigter Belegreife innerhalb von ca. 2 Wochen. Inklusive erforderlicher Zusatzmittel und Bindemittel.', 'd6e77858-bb87-431e-9da6-ff224e0cca58'::uuid, 'm²', 0, true, null, '2026-06-24 13:13:31.252152+00'::timestamptz, '2026-06-24 13:13:31.252152+00'::timestamptz, null, null, 20, 'Hero ID: 518321 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 13, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('f977d59c-615f-478a-a857-dcb30e7ea44a'::uuid, '07-087', 'Aufpreis für Einlegen von Dampfbremse in feuchten Bereichen', 'Aufpreis für Einlegen von Dampfbremse in feuchten Bereichen', 'Zusätzliche Abdichtungsmaßnahme durch Einlegen einer Dampfbremse in feuchtigkeitsbelasteten Räumen zur Vermeidung von Dampfdiffusion und Kondensatbildung. Die Dampfbremse wird vollflächig unter Estrich- oder Trockenbauschichten verlegt und an allen Anschlüssen fachgerecht verklebt und abgedichtet.
