('49cea238-5c1a-4435-beb8-adab8437f7d5'::uuid, '07-090', 'WC-Spülkasten einbetonieren und mit Gipskarton verkleiden', 'WC-Spülkasten einbetonieren und mit Gipskarton verkleiden', 'Bereits durch den Installateur eingebauten Unterputz-WC-Spülkasten fachgerecht im Mauerwerk einbetonieren, ausrichten und stabil fixieren. Anschließend doppelte Beplankung mit imprägnierten Gipskartonplatten herstellen, alle Fugen verspachteln und die Oberfläche fliesenfertig vorbereiten. Inklusive sämtlicher Kleinmaterialien wie Befestigungen, Schrauben, Mörtel und Spachtelmasse.', 'd6e77858-bb87-431e-9da6-ff224e0cca58'::uuid, 'Stk', 0, true, null, '2026-06-24 13:13:33.982281+00'::timestamptz, '2026-06-24 13:13:33.982281+00'::timestamptz, null, null, 20, 'Hero ID: 518336 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 406.33, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('2f911c9d-4058-43ee-b33f-080a98f3596f'::uuid, '07-095', 'Herstellen von Hohlkehle zwischen Decke und Wand, Radius 10 cm', 'Herstellen von Hohlkehle zwischen Decke und Wand, Radius 10 cm', 'Zwischen Decke und Wand wird eine gleichmäßige Hohlkehle mit einem Radius von 10 cm aus hochwertigem Kalk-Zement-Mörtel fachgerecht hergestellt. Die Oberfläche wird glatt abgezogen und zur weiteren Beschichtung vorbereitet.', 'd6e77858-bb87-431e-9da6-ff224e0cca58'::uuid, 'lfm', 0, true, null, '2026-06-24 13:13:35.402468+00'::timestamptz, '2026-06-24 13:13:35.402468+00'::timestamptz, null, null, 20, 'Hero ID: 518357 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 30.23, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('2f8541af-ee2d-4a81-87e6-a23e6dd9ee6b'::uuid, '07-096', 'Verputzarbeiten im Stiegenhaus nach Installationen', 'Verputzarbeiten im Stiegenhaus nach Installationen', 'Im Bereich des Stiegenhauses werden nach Abschluss der Installationsarbeiten sämtliche Beschädigungen an Wand- und Deckenflächen fachgerecht ausgebessert. Die Flächen werden mit Kalk-Zement-Putzmörtel in grob und fein verputzt und für nachfolgende Malerarbeiten vorbereitet.', 'd6e77858-bb87-431e-9da6-ff224e0cca58'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:13:36.247274+00'::timestamptz, '2026-06-24 13:13:36.247274+00'::timestamptz, null, null, 20, 'Hero ID: 518359 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('f03e4227-8690-491e-b8c5-f1945de50ff1'::uuid, '07-100', 'Stahlzarge liefern und montieren', 'Stahlzarge liefern und montieren', 'Liefern und fachgerechtes Montieren einer Standard-Stahlzarge 70–100 x 200 cm für Wandstärken von 10 – 20 cm, einschließlich Ausrichten, Verdübeln und Hinterfüllen mit Mörtel oder Montageschaum. Nach der Montage werden alle Anschlussfugen sauber verspachtelt und flächenbündig für die Endbeschichtung vorbereitet. Inklusive Dichtung und sämtlicher Befestigungsmaterialien.
Angebotenes Produkt: Stahlzarge Standard, Weiß grundiert', 'd6e77858-bb87-431e-9da6-ff224e0cca58'::uuid, 'Stk', 0, true, null, '2026-06-24 13:13:38.159312+00'::timestamptz, '2026-06-24 13:13:38.159312+00'::timestamptz, null, null, 20, 'Hero ID: 518345 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 209.6, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('625ea3d2-50a2-4a3d-bff0-a520d16e3183'::uuid, '07-110', 'Verputzarbeiten auf Fassade nach Lüftungsdurchbruch inkl. Gerüst und Absicherung', 'Verputzarbeiten auf Fassade nach Lüftungsdurchbruch inkl. Gerüst und Absicherung', 'Nach dem Herstellen eines Lüftungsdurchbruchs wird der Fassadenbereich fachgerecht wieder verputzt. Dabei werden lose Putzteile entfernt, der Untergrund gereinigt und mit geeignetem Haftgrund vorbereitet. Anschließend erfolgt das Ausbessern der Putzstelle mit witterungsbeständigem Fassadenputz in der passenden Struktur. Die Arbeiten beinhalten sämtliche erforderlichen Nebenleistungen, einschließlich Absicherung des Arbeitsbereichs und Bereitstellung von Arbeitsgerüst.', 'd6e77858-bb87-431e-9da6-ff224e0cca58'::uuid, 'Stk', 0, true, null, '2026-06-24 13:13:39.550203+00'::timestamptz, '2026-06-24 13:13:39.550203+00'::timestamptz, null, null, 20, 'Hero ID: 518363 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 299.67, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
