('f921c06a-603a-4d85-b289-fc4c4a2abc48'::uuid, '11-110', 'Zuschneiden beigestellter Fliesen für Sockelverlegung', 'Zuschneiden beigestellter Fliesen für Sockelverlegung', 'Beigestellte keramische oder Feinsteinzeugfliesen auf das erforderliche Sockelmaß zuschneiden. Kanten werden sauber geschnitten und entgratet, sodass ein exakter Anschluss an den Bodenbelag gewährleistet ist. Der Zuschnitt erfolgt staubarm und maßgenau.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'lfm', 0, true, null, '2026-06-24 13:17:26.705533+00'::timestamptz, '2026-06-24 13:17:26.705533+00'::timestamptz, null, null, 20, 'Hero ID: 522442 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 6.12, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('b8cd6201-bd08-4ece-8e0d-724820954434'::uuid, '11-111', 'Sockelfliesen verlegen', 'Sockelfliesen verlegen', 'Beigestellte keramische oder Feinsteinzeugfliesen als Sockelleiste fachgerecht auf Wandflächen verlegen. Der Untergrund wird gereinigt und grundiert, die zugeschnittenen Fliesen werden im Dünnbettverfahren gesetzt und die Stoßfugen gleichmäßig ausgeführt. Sauberer Anschluss an Bodenfliesen und Ecken gewährleistet ein optisch harmonisches Gesamtbild.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'lfm', 0, true, null, '2026-06-24 13:17:27.566443+00'::timestamptz, '2026-06-24 13:17:27.566443+00'::timestamptz, null, null, 20, 'Hero ID: 522444 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 6.12, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('24d85585-8ea0-4ecf-8f35-0ace2229f6ed'::uuid, '11-130', 'Aufpreis für Verlegen von Natursteinfliesen bis 10 mm Stärke', 'Aufpreis für Verlegen von Natursteinfliesen bis 10 mm Stärke', 'Aufpreis für das fachgerechte Verlegen von Natursteinfliesen bis 10 mm Stärke. Inklusive sorgfältiger Auswahl und Anpassung der Platten, Verwendung eines natursteinverträglichen Flexklebers sowie präziser Verlegung mit gleichmäßigem Fugenbild. Kanten und Schnittstellen werden sauber nachbearbeitet, um eine hochwertige Oberfläche zu erzielen.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'm²', 0, true, null, '2026-06-24 13:17:28.511055+00'::timestamptz, '2026-06-24 13:17:28.511055+00'::timestamptz, null, null, 20, 'Hero ID: 522447 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 24.4, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('5625064d-e97b-496d-92e5-de98bc0c9126'::uuid, '11-140', 'Aufpreis für Verlegen von Mosaikfliesen', 'Aufpreis für Verlegen von Mosaikfliesen', 'Aufpreis für das präzise Verlegen von Mosaikfliesen auf Wand- oder Bodenflächen. Inklusive sorgfältiger Vorbereitung des Untergrunds, passgenauer Ausrichtung der Mosaikmatten, Einhaltung eines gleichmäßigen Fugenbilds und Anpassung an Aussparungen und Randbereiche. Verwendung von feinkörnigem, flexibel einstellbarem Fliesenkleber für optimale Haftung und saubere Oberfläche.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'm²', 0, true, null, '2026-06-24 13:17:29.59945+00'::timestamptz, '2026-06-24 13:17:29.59945+00'::timestamptz, null, null, 20, 'Hero ID: 522449 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 67.47, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('0c0690e6-5859-4cfa-888c-a92c05f19061'::uuid, '11-150', 'Aufpreis für Einlegen von Kantenschutzschienen', 'Aufpreis für Einlegen von Kantenschutzschienen', 'Aufpreis für das fachgerechte Einlegen und Anarbeiten von Kantenschutzschienen bei Fliesenabschlüssen und Außenecken. Inklusive Zuschneiden, Einpassen, Einspachteln und Ausrichten im exakten Lot. Saubere Übergänge und gleichmäßige Fugen gewährleisten ein hochwertiges Gesamtbild.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'lfm', 0, true, null, '2026-06-24 13:17:30.532565+00'::timestamptz, '2026-06-24 13:17:30.532565+00'::timestamptz, null, null, 20, 'Hero ID: 522471 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 37.67, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('3b7d1e75-1cf1-4793-afff-4cbe421019bf'::uuid, '11-160', 'Aufpreis für Herstellen von Gehrungsschnitt bei sichtbaren Kanten', 'Aufpreis für Herstellen von Gehrungsschnitt bei sichtbaren Kanten', 'Aufpreis für das Herstellen von präzisen Gehrungsschnitten bei sichtbaren Kanten von keramischen oder Feinsteinzeugfliesen. Die Schnittkanten werden im 45°-Winkel exakt ausgeführt, geschliffen und entgratet, um saubere Eckausbildungen ohne Kantenschutzschienen zu erzielen. Besonders geeignet für hochwertige, optisch durchgehende Fliesenabschlüsse.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'lfm', 0, true, null, '2026-06-24 13:17:33.555524+00'::timestamptz, '2026-06-24 13:17:33.555524+00'::timestamptz, null, null, 20, 'Hero ID: 522477 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 22.7, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('1a00f720-80a9-4942-a1f6-22aba3656b90'::uuid, '11-170', 'Aufpreis für U-Profil bei Verglasung, bündig mit Fliesen', 'Aufpreis für U-Profil bei Verglasung, bündig mit Fliesen', 'Liefern und montieren eines U-Profils bis 250 cm Höhe für Verglasungen, bündig mit Fliesen ausgeführt. Geeignet für Glasstärken von 8 – 10 mm und Fliesenstärken von 7 – 11 mm. Inklusive präzisem Zuschnitt, Befestigung, Abdichtung der Anschlussfugen sowie sauberen Übergängen zu Wandfliesen.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'Stk', 0, true, null, '2026-06-24 13:17:34.831362+00'::timestamptz, '2026-06-24 13:17:34.831362+00'::timestamptz, null, null, 20, 'Hero ID: 524810 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 278, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('f4879962-b31c-4c45-8956-b68a31293c3e'::uuid, '11-171', 'U-Profil mit Gefällekeil für Verglasung bei Duschrinne', 'U-Profil mit Gefällekeil für Verglasung bei Duschrinne', 'Liefern und montieren eines U-Profils mit integriertem Gefällekeil (bis 148 cm Länge) für Verglasungen bei Duschrinnen, bündig mit den Fliesen ausgeführt. Geeignet für Glasstärken von 8 – 10 mm und Fliesenstärken von 7 – 11 mm. Inklusive präzisem Zuschnitt, Ausrichtung im Gefälle, Befestigung, Abdichtung der Anschlussfugen und sauberen Übergängen zu den angrenzenden Fliesenflächen.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'Stk', 0, true, null, '2026-06-24 13:17:35.65504+00'::timestamptz, '2026-06-24 13:17:35.65504+00'::timestamptz, null, null, 20, 'Hero ID: 524814 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 331.27, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('b8eacb7e-c5e5-4b17-93b6-55a529e77bba'::uuid, '11-175', 'Magnettürchen mit verfliesbarer Oberfläche', 'Magnettürchen mit verfliesbarer Oberfläche', 'Liefern und montieren eines Magnettürchens mit verfliesbarer Oberfläche für Revisionsöffnungen in verfliesten Wandflächen. Das Türchen wird bündig in die Fliesenfläche integriert und ermöglicht einen unsichtbaren Zugang zu Wartungsbereichen. Inklusive passgenauem Zuschneiden, Einsetzen, Magnethalterung, Dichtband, Verfugung und fachgerechtem Abschluss.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'Stk', 0, true, null, '2026-06-24 13:17:36.50298+00'::timestamptz, '2026-06-24 13:17:36.50298+00'::timestamptz, null, null, 20, 'Hero ID: 524818 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 235, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('f49e31d8-63a1-49cd-ae78-dbd65815cbcd'::uuid, '11-180', 'Aufpreis für Fliesenverlegung im Küchenrückwandbereich nach Küchenmontage', 'Aufpreis für Fliesenverlegung im Küchenrückwandbereich nach Küchenmontage', 'Nachträgliches Verlegen von Wandfliesen im Bereich des Küchenspiegels nach der Montage der Küche. Inklusive präzisem Zuschneiden der Fliesen rund um Steckdosen, Armaturen und Oberschränke sowie fachgerechtem Verfugen. Alle Arbeiten werden sauber und staubarm ausgeführt.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:17:37.554632+00'::timestamptz, '2026-06-24 13:17:37.554632+00'::timestamptz, null, null, 20, 'Hero ID: 522459 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 402, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('459c32b6-b244-4cd6-ad9b-974543ab78e3'::uuid, '11-190', 'Aufpreis für verfliesten Duschbereich mit Duschrinne', 'Aufpreis für verfliesten Duschbereich mit Duschrinne', 'Aufpreis für das Herstellen eines verfliesten Duschbereichs anstelle einer Duschtasse. Inklusive genauer Positionierung und Einbau der Duschrinne, Herstellung des Gefälles im Bodenbereich, fachgerechter Abdichtung mit Dichtband und Dichtecken sowie Einbindung der Fliesenarbeiten in das Gesamtsystem.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:17:38.915958+00'::timestamptz, '2026-06-24 13:17:38.915958+00'::timestamptz, null, null, 20, 'Hero ID: 522452 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 358, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('149bff87-4e2e-4d97-b62a-cdde8a72b776'::uuid, '11-200', 'Neu verlegte Fliesen imprägnieren', 'Neu verlegte Fliesen imprägnieren', 'Neu verlegte keramische oder Feinsteinzeugfliesen sowie Natursteinflächen mit einer geeigneten, transparenten Imprägnierung behandeln. Die Imprägnierung reduziert die Wasser- und Schmutzaufnahme und erleichtert die Reinigung. Die Fläche wird gereinigt, gleichmäßig behandelt und nach Trocknung poliert, um eine gleichmäßige Oberfläche zu erzielen.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'm²', 0, true, null, '2026-06-24 13:17:40.382011+00'::timestamptz, '2026-06-24 13:17:40.382011+00'::timestamptz, null, null, 20, 'Hero ID: 522451 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 7.27, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('40f32968-7562-4cfa-92fb-450fc95176cc'::uuid, '11-210', 'Erneuerung von dauerelastischen Silikonfugen', 'Erneuerung von dauerelastischen Silikonfugen', 'Bestehende, gealterte oder verschmutzte Silikonfugen fachgerecht entfernen und Neuverfugung mit hochwertigem, dauerelastischem Sanitärsilikon ausführen. Inklusive gründlicher Reinigung der Fugenränder, Primerauftrag bei Bedarf sowie exakter Glättung der neuen Fuge für einen sauberen und langlebigen Abschluss.

Angebotenes Produkt: Cimsec Fugenflex SE', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'lfm', 0, true, null, '2026-06-24 13:17:41.329235+00'::timestamptz, '2026-06-24 13:17:41.329235+00'::timestamptz, null, null, 20, 'Hero ID: 524828 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 13.37, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('bcf9d773-0f23-433f-892a-908cf41d179a'::uuid, '11-250', 'Vertragen von Wand- oder Bodenfliesen vom Anlieferpunkt zur Baustelle', 'Vertragen von Wand- oder Bodenfliesen vom Anlieferpunkt zur Baustelle', 'Fachgerechtes Vertragen von Wand- oder Bodenfliesen vom Anlieferpunkt bis zur Baustelle, inklusive schonendem Transport mit Tragehilfen und Schutz der Verkehrswege mit Abdeckvlies, sachgerechte Handhabung und Zwischenlagerung durch geschultes Personal.', '5cbed187-1fb3-4c07-ac17-a44600dbc736'::uuid, 'm²', 0, true, null, '2026-06-24 13:17:42.920659+00'::timestamptz, '2026-06-24 13:17:42.920659+00'::timestamptz, null, null, 20, 'Hero ID: 524836 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 7.13, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
