('59a60c18-a027-48d5-b892-35e7cee11e14'::uuid, '12-210', 'Parkettreparatur im Bereich eines ehemaligen Ofenplatzes', 'Parkettreparatur im Bereich eines ehemaligen Ofenplatzes', 'Öffnen des bestehenden Parkettbodens im Bereich eines ehemaligen Ofenstandorts, Entfernen loser oder beschädigter Stäbe, passgenaues Einsetzen geeigneter Ersatzelemente, Verleimung und bündiges Nachsetzen an den Bestand.', '4c26cf88-f39a-427f-aa02-4b5cd1d77c9b'::uuid, 'Stk', 0, true, null, '2026-06-24 13:18:31.679207+00'::timestamptz, '2026-06-24 13:18:31.679207+00'::timestamptz, null, null, 20, 'Hero ID: 524867 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 455, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
('4e45f7fb-caf8-43d5-bf64-80f312fa4070'::uuid, '12-220', 'Parkettboden mit Bauschaum unterschäumen', 'Parkettboden mit Bauschaum unterschäumen', 'Bestehenden, hohl liegenden oder federnden Parkettboden punktuell anbohren und die Hohlräume unter dem Parkett mit geeignetem PU-Bauschaum verfüllen, um die Stabilität zu verbessern und Knarrgeräusche zu reduzieren. Überschüssigen Schaum nach Aushärtung entfernen, Bohrlöcher mit Holzkitt verschließen.', '4c26cf88-f39a-427f-aa02-4b5cd1d77c9b'::uuid, 'm²', 0, true, null, '2026-06-24 13:18:32.885982+00'::timestamptz, '2026-06-24 13:18:32.885982+00'::timestamptz, null, null, 20, 'Hero ID: 524870 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 11.7, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
