('d456b92a-083c-4319-952c-e003967322b9'::uuid, '12-250', 'Weiße Verkleidung bei Heizkörperrohren', 'Weiße Verkleidung bei Heizkörperrohren', 'Liefern und montieren einer weißen, lackierten Verkleidung zur sauberen Abdeckung sichtbarer Heizkörperrohre. Inklusive Zuschneiden, Anpassen an Rohrverlauf, verdeckte Befestigung und sauberer Abschluss gegen Wand und Boden. Oberfläche weiß lackiert, stoßfest und pflegeleicht.', '4c26cf88-f39a-427f-aa02-4b5cd1d77c9b'::uuid, 'lfm', 0, true, null, '2026-06-24 13:18:35.913562+00'::timestamptz, '2026-06-24 13:18:35.913562+00'::timestamptz, null, null, 20, 'Hero ID: 524919 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 62.4, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
