('8ba09260-dc35-4bc1-a2b0-db3e5cf4b54d'::uuid, '13-001', 'Bauschlussreinigung besenrein', 'Bauschlussreinigung besenrein', 'Bauschlussreinigung sämtlicher Flächen besenrein, einschließlich Entstauben und Zusammenkehren aller Boden-, Wand- und Deckenflächen. Entfernen von grobem Bauschmutz, losem Staub und Verpackungsresten. Reinigung erfolgt manuell mit geeigneten Besen, Bürsten und Industriestaubsaugern.', 'd7f88602-e4dd-4211-85f0-db3c82714a50'::uuid, 'pauschal', 0, true, null, '2026-06-24 13:19:06.964831+00'::timestamptz, '2026-06-24 13:19:06.964831+00'::timestamptz, null, null, 20, 'Hero ID: 524959 · Import aus bau4you.catalog am 2026-06-24', 0, 0, 0, 'artikel', false, 'kein', 0, 0, null, 0, (select id from public.organizations order by created_at asc limit 1), false, false, false, false, null, null, null),
